code = """import json
import re
from collections import defaultdict

children_books = var_functions.query_db:40

with open(var_functions.query_db:14, 'r') as f:
    reviews_2020 = json.load(f)

book_titles = {}
for book in children_books:
    book_titles[book['book_id']] = book['title']

book_ratings = defaultdict(list)

for review in reviews_2020:
    pid = review['purchase_id']
    m = re.search(r'purchaseid_(\d+)', pid)
    if m:
        book_id = 'bookid_' + m.group(1)
        if book_id in book_titles:
            rating = float(review['rating'])
            book_ratings[book_id].append(rating)

filtered_books = []
for book_id in book_ratings:
    ratings = book_ratings[book_id]
    avg = sum(ratings) / len(ratings)
    if avg >= 4.5:
        filtered_books.append([book_titles[book_id], round(avg, 2), len(ratings)])

filtered_books.sort(key=lambda x: (-x[1], -x[2]))

output = []
if not filtered_books:
    output.append("No children's books meet the 4.5 rating threshold.")
else:
    output.append("Children's books with average rating >= 4.5 (2020+ reviews):")
    for item in filtered_books:
        output.append("- " + item[0] + " (Avg: " + str(item[1]) + ", Reviews: " + str(item[2]) + ")")

result_str = "\n".join(output)
final_dict = {"answer": result_str}
print('__RESULT__:')
print(json.dumps(final_dict))"""

